using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

// Train and save the model
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label",
        new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
        inputColumnName: "Churned")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

// For production, use TrainTestSplit with a larger dataset:
// var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2);
var model = pipeline.Fit(rawData);
mlContext.Model.Save(model, rawData.Schema, modelPath);

Console.WriteLine("Model trained and saved to {0}", modelPath);

// Register the pooled prediction engine (thread-safe for web apps)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API â€” POST to /predict");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedChurned,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

